                        new_population[i] = mutated
                        fitness[i] = f_mut
                        if f_mut < self.f_opt:
                            self.f_opt = f_mut
                            self.x_opt = mutated

            # Dynamic mutation phase
            if evaluations + self.pop_size <= self.budget:
